// Validate URL and extract metadata
const input = $input.first().json;
const url = input.url || '';
const importId = input.importId || '';
const callbackUrl = input.callbackUrl || '';
const callbackSecret = input.callbackSecret || '';
const platform = input.platform || 'blog';

if (!url || !importId || !callbackUrl) {
  throw new Error('Missing required fields: url, importId, callbackUrl');
}

try {
  new URL(url);
} catch (e) {
  throw new Error('Invalid URL: ' + url);
}

return {
  json: {
    url,
    importId,
    callbackUrl,
    callbackSecret,
    platform,
    domain: new URL(url).hostname.replace('www.', '')
  }
};

// Try to extract JSON-LD Recipe structured data from HTML
const html = $input.first().json.data || $input.first().json.body || '';
const url = $('Validate URL').first().json.url;
const importId = $('Validate URL').first().json.importId;
const callbackUrl = $('Validate URL').first().json.callbackUrl;
const callbackSecret = $('Validate URL').first().json.callbackSecret;

// Check for fetch error
if (!html || html.length < 100) {
  return {
    json: {
      hasJsonLd: false,
      rawText: '',
      importId,
      callbackUrl,
      callbackSecret,
      url,
      error: 'Failed to fetch page content'
    }
  };
}

// Extract JSON-LD scripts
const jsonLdRegex = /<script[^>]*type=["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/gi;
let match;
let recipe = null;

while ((match = jsonLdRegex.exec(html)) !== null) {
  try {
    let parsed = JSON.parse(match[1].trim());

    // Handle @graph arrays
    if (parsed['@graph']) {
      parsed = parsed['@graph'];
    }

    // Ensure it's an array
    const items = Array.isArray(parsed) ? parsed : [parsed];

    for (const item of items) {
      if (item['@type'] === 'Recipe' || 
          (Array.isArray(item['@type']) && item['@type'].includes('Recipe'))) {
        recipe = item;
        break;
      }
    }
    if (recipe) break;
  } catch (e) {
    // Invalid JSON-LD, skip
  }
}

// Extract title from HTML as fallback
const titleMatch = html.match(/<title[^>]*>([^<]+)<\/title>/i);
const htmlTitle = titleMatch ? titleMatch[1].trim() : '';

if (recipe) {
  // Parse JSON-LD Recipe into our format
  const ingredients = (recipe.recipeIngredient || []).map((ing, i) => {
    // Basic parsing: try to split quantity/unit from name
    const text = typeof ing === 'string' ? ing : '';
    return {
      name: text,
      canonicalName: text,
      quantity: null,
      unit: null,
      optional: false
    };
  });

  const steps = [];
  const instructions = recipe.recipeInstructions || [];
  if (Array.isArray(instructions)) {
    for (const step of instructions) {
      if (typeof step === 'string') {
        steps.push(step);
      } else if (step.text) {
        steps.push(step.text);
      } else if (step.itemListElement) {
        for (const sub of step.itemListElement) {
          if (sub.text) steps.push(sub.text);
          else if (typeof sub === 'string') steps.push(sub);
        }
      }
    }
  } else if (typeof instructions === 'string') {
    steps.push(instructions);
  }

  // Parse ISO 8601 duration (e.g., PT30M, PT1H15M)
  function parseDuration(dur) {
    if (!dur) return null;
    const match = dur.match(/PT(?:(\d+)H)?(?:(\d+)M)?/);
    if (!match) return null;
    return (parseInt(match[1] || '0') * 60) + parseInt(match[2] || '0');
  }

  const parsedRecipe = {
    title: recipe.name || htmlTitle || 'Untitled Recipe',
    servings: recipe.recipeYield ? parseInt(String(recipe.recipeYield)) || null : null,
    prepTimeMinutes: parseDuration(recipe.prepTime),
    cookTimeMinutes: parseDuration(recipe.cookTime),
    ingredients: ingredients,
    steps: steps,
    imageUrl: Array.isArray(recipe.image) ? recipe.image[0] : (recipe.image?.url || recipe.image || null)
  };

  return {
    json: {
      hasJsonLd: true,
      parsedRecipe,
      importId,
      callbackUrl,
      callbackSecret,
      url,
      rawText: html.substring(0, 5000)
    }
  };
}

// No JSON-LD found — strip HTML to text for GPT
const textContent = html
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<nav[\s\S]*?<\/nav>/gi, '')
  .replace(/<footer[\s\S]*?<\/footer>/gi, '')
  .replace(/<header[\s\S]*?<\/header>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .substring(0, 6000);

return {
  json: {
    hasJsonLd: false,
    rawText: textContent,
    htmlTitle,
    importId,
    callbackUrl,
    callbackSecret,
    url
  }
};

